const { ApolloServer, gql, PubSub } = require('apollo-server');
const { createServer } = require('http');
const { WebSocketServer } = require('ws');
const { useServer } = require('graphql-ws/lib/use/ws');

const pubsub = new PubSub();
const MESSAGE_ADDED = 'MESSAGE_ADDED';

const typeDefs = gql`
  type Message {
    id: ID!
    content: String!
    roomId: ID!
  }

  type Query {
    messages(roomId: ID!): [Message]
  }

  type Mutation {
    sendMessage(roomId: ID!, content: String!): Message
  }

  type Subscription {
    messageAdded(roomId: ID!): Message
  }
`;

const resolvers = {
  Query: {
    messages: (parent, { roomId }) => {
      return messages.filter(message => message.roomId === roomId);
    },
  },
  Mutation: {
    sendMessage: (parent, { roomId, content }) => {
      const message = { id: Date.now().toString(), content, roomId };
      messages.push(message);
      pubsub.publish(MESSAGE_ADDED, { messageAdded: message, roomId });
      return message;
    },
  },
  Subscription: {
    messageAdded: {
      subscribe: (parent, { roomId }) => {
        return pubsub.asyncIterator([MESSAGE_ADDED]);
      },
    },
  },
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    // Implement authentication and authorization here
    return {};
  },
});

const httpServer = createServer(server);
const wsServer = new WebSocketServer({
  server: httpServer,
  path: server.graphqlPath,
});

useServer({ schema: server.schema }, wsServer);

const messages = [];

httpServer.listen(4000, () => {
  console.log('Server is running on http://localhost:4000/graphql');
});